import React from 'react';
import { useNavigate } from 'react-router-dom';
import he from '../i18n/he.json';

export default function Cart() {
  const navigate = useNavigate();
  const cart = JSON.parse(localStorage.getItem('cart') || '{}');

  if (!cart.toppings) {
    return (
      <div className="max-w-md mx-auto mt-10 p-6 bg-white rounded-lg shadow-lg text-center">
        <h2 className="text-xl mb-4">{he.cart}</h2>
        <p>העגלה ריקה</p>
      </div>
    );
  }

  return (
    <div className="max-w-md mx-auto mt-10 p-6 bg-white rounded-lg shadow-lg">
      <h2 className="text-xl mb-4 text-tomato">{he.cart}</h2>
      <div className="mb-2 flex justify-between">
        <span>{he.base_pizza}</span>
        <span>30 ₪</span>
      </div>
      {cart.toppings.length > 0 && (
        <div className="mb-2">
          <div className="font-semibold">{he.toppings}:</div>
          <ul className="list-disc pr-5">
            {cart.toppings.map((topping) => (
              <li key={topping}>{topping} <span className="text-xs">(+8 ₪)</span></li>
            ))}
          </ul>
        </div>
      )}
      <div className="font-bold text-lg mt-4 flex justify-between">
        <span>{he.total}:</span>
        <span>{cart.total} ₪</span>
      </div>
      <button
        className="w-full bg-tomato text-white py-2 rounded-lg font-bold text-lg mt-4 hover:bg-red-700 transition"
        onClick={() => navigate('/checkout')}
      >
        {he.checkout}
      </button>
    </div>
  );
}
